{
  "plan": [
    {
      "tool": "datadog.query_metric",
      "arguments": {
        "query": "avg:aws.cloudwatch.metrics{*} by {service}",
        "from": "now-1h",
        "to": "now",
        "resolution": "1m"
      },
      "depends_on": []
    },
    {
      "tool": "datadog.list_alerts",
      "arguments": {
        "filter": {
          "status": ["triggered", "warn"],
          "source": "cloudwatch"
        },
        "limit": 50
      },
      "depends_on": []
    },
    {
      "tool": "datadog.query_metric",
      "arguments": {
        "query": "avg:aws.cloudwatch.alarm.state{*} by {alarm_name,service,threshold,state_updated_timestamp}",
        "from": "now-1h",
        "to": "now"
      },
      "depends_on": []
    },
    {
      "tool": "iam.check_permission",
      "arguments": {
        "resource": "s3://cloudwatch-logs-bucket",
        "action": "read",
        "context": {
          "triggered_alarms": "$2.alerts",
          "affected_service": "$1.results"
        }
      },
      "depends_on": [1, 2]
    },
    {
      "tool": "file.read",
      "arguments": {
        "path": "s3://cloudwatch-logs-bucket/logs/$1.results[0].service/latest.log",
        "format": "text",
        "lines": 500
      },
      "depends_on": [4]
    },
    {
      "tool": "slack.post_message",
      "arguments": {
        "channel": "#incidents-general",
        "message": "🚨 *Incident Detected — Creating Incident Channel*\n\n*Affected Service:* `$1.results[0].service`\n*Alarm Name:* `$2.alerts[0].name`\n*Alarm State:* `$2.alerts[0].status`\n*Threshold Breached:* `$3.results[0].threshold`\n*State Timestamp:* `$2.alerts[0].triggered_at`\n\nInitializing incident response workflow..."
      },
      "depends_on": [1, 2, 3]
    },
    {
      "tool": "slack.post_message",
      "arguments": {
        "channel": "#incident-$1.results[0].service-response",
        "message": "🔴 *INCIDENT RESPONSE INITIATED*\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━\n*📌 Affected Service:* `$1.results[0].service`\n*🔔 Alarm Name:* `$2.alerts[0].name`\n*⚠️ Alarm State:* `$2.alerts[0].status`\n*📊 Threshold:* `$3.results[0].threshold`\n*🕐
